import './PopoverOnboarding.scss';

import { Icon } from ':components/Icon';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React from 'react';

import type { PopoverOnboardingProps } from './PopoverOnboarding.types';
import { Slides } from './Slides';
import { Slide } from './Slides/Slide';

export const PopoverOnboarding: FC<PopoverOnboardingProps> = ({
	open,
	activeSlideIndex = 0,
	onClose,
	className,
	onPaginationChange,
	content,
	...props
}) => {
	const isSlides = Array.isArray(content);

	return (
		<div
			{...props}
			className={classNames('dsb_onboarding inverseTheme', open && 'dsb_onboarding__open', className)}
			data-testid="PopoverOnboarding"
		>
			{onClose && <Icon iconName={Icons.Close} size="large" onClick={onClose} className="dsb_onboarding-icon-close" />}
			{isSlides && (
				<Slides content={content} activeSlideIndex={activeSlideIndex} onPaginationChange={onPaginationChange} />
			)}
			{!isSlides && <Slide {...content} />}
		</div>
	);
};
